1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	const CURSED_SURCHARGE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_BASE = 60;
22	const BLOCK_SIZE = 3;
23	const LOYALTY_YEARS_THRESHOLD = 2;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	
26	function withFirstInsurance(base: number): number {
27	  return base + base * FIRST_INSURANCE_SURCHARGE;
28	}
29	
30	function itemBase(item: Item): number {
31	  return BASE_PREMIUMS[item.type];
32	}
33	
34	function groupByType(items: Item[]): Map<string, Item[]> {
35	  const groups = new Map<string, Item[]>();
36	  for (const item of items) {
37	    const list = groups.get(item.type) ?? [];
38	    list.push(item);
39	    groups.set(item.type, list);
40	  }
41	  return groups;
42	}
43	
44	function componentGroupBase(group: Item[]): number {
45	  const blocks = Math.floor(group.length / BLOCK_SIZE);
46	  const remainder = group.length - blocks * BLOCK_SIZE;
47	  return blocks * BLOCK_BASE + remainder * itemBase(group[0]);
48	}
49	
50	function componentsTotal(items: Item[]): number {
51	  let total = 0;
52	  for (const [, group] of groupByType(items)) {
53	    total += withFirstInsurance(componentGroupBase(group));
54	  }
55	  return total;
56	}
57	
58	function surchargeWhen(condition: boolean, base: number, rate: number): number {
59	  return condition ? base * rate : 0;
60	}
61	
62	function itemPremium(item: Item): number {
63	  const base = itemBase(item);
64	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
65	  const curseSurcharge = surchargeWhen(item.cursed === true, base, CURSED_SURCHARGE);
66	  const enchantmentSurcharge = surchargeWhen(isHighlyEnchanted, base, HIGH_ENCHANTMENT_SURCHARGE);
67	  return withFirstInsurance(base) + curseSurcharge + enchantmentSurcharge;
68	}
69	
70	function policyBasePremium(items: Item[]): number {
71	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
72	  const others = items.filter((item) => !COMPONENT_TYPES.has(item.type));
73	  const othersBase = others.reduce((sum, item) => sum + itemBase(item), 0);
74	  let componentsBase = 0;
75	  for (const [, group] of groupByType(components)) {
76	    componentsBase += componentGroupBase(group);
77	  }
78	  return othersBase + componentsBase;
79	}
80	
81	function quotePremium(items: Item[], yearsWithMHPCO: number): number {
82	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
83	  const others = items.filter((item) => !COMPONENT_TYPES.has(item.type));
84	  const othersTotal = others.reduce(
85	    (sum, item) => sum + itemPremium(item),
86	    0,
87	  );
88	  const loyaltyDiscount =
89	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
90	      ? policyBasePremium(items) * LOYALTY_DISCOUNT_RATE
91	      : 0;
92	  return Math.ceil(
93	    othersTotal + componentsTotal(components) - loyaltyDiscount + PROCESSING_FEE,
94	  );
95	}
96	
97	export function runScenario(scenario: Scenario): { results: { premium: number }[] } {
98	  const results = scenario.steps.map((step) => ({
99	    premium: quotePremium(step.items, scenario.customer.yearsWithMHPCO),
100	  }));
101	  return { results };
102	}
