function surchargeWhen(condition: boolean, base: number, rate: number): number {
  return condition ? base * rate : 0;
}

function itemPremium(item: Item): number {
  const base = itemBase(item);
  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
  const curseSurcharge = surchargeWhen(item.cursed === true, base, CURSED_SURCHARGE);
  const enchantmentSurcharge = surchargeWhen(isHighlyEnchanted, base, HIGH_ENCHANTMENT_SURCHARGE);
  return withFirstInsurance(base) + curseSurcharge + enchantmentSurcharge;
}

function partitionItems(items: Item[]): { components: Item[]; others: Item[] } {
  const components: Item[] = [];
  const others: Item[] = [];
  for (const item of items) {
    (COMPONENT_TYPES.has(item.type) ? components : others).push(item);
  }
  return { components, others };
}

function componentGroupBases(components: Item[]): number[] {
  const bases: number[] = [];
  for (const [, group] of groupByType(components)) {
    bases.push(componentGroupBase(group));
  }
  return bases;
}

function quotePremium(items: Item[], yearsWithMHPCO: number): number {
  const { components, others } = partitionItems(items);
  const groupBases = componentGroupBases(components);
  const othersTotal = others.reduce((sum, item) => sum + itemPremium(item), 0);
  const componentsTotal = groupBases.reduce(
    (sum, base) => sum + withFirstInsurance(base),
    0,
  );
  const policyBase =
    others.reduce((sum, item) => sum + itemBase(item), 0) +
    groupBases.reduce((sum, base) => sum + base, 0);
  const loyaltyDiscount = surchargeWhen(
    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
    policyBase,
    LOYALTY_DISCOUNT_RATE,
  );
  return Math.ceil(othersTotal + componentsTotal - loyaltyDiscount + PROCESSING_FEE);
}
